import{_ as a,o as b,c as e,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const C=JSON.parse('{"title":"凝视","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/凝视.md","filePath":"4.资源分区/7.物品与装备/6.套装/凝视.md"}'),n={name:"4.资源分区/7.物品与装备/6.套装/凝视.md"};function o(_,p,l,d,i,c){return b(),e("div",null,[...p[0]||(p[0]=[r("h1",{id:"凝视",tabindex:"-1"},[t("凝视 "),r("a",{class:"header-anchor",href:"#凝视","aria-label":'Permalink to "凝视"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),s('<h1 id="凝视-1" tabindex="-1">凝视 <a class="header-anchor" href="#凝视-1" aria-label="Permalink to &quot;凝视&quot;">​</a></h1><p>凝视</p><p>武器<br> 价格：C+1000<br> 在机器的锁眼之中，你能感受到一只令人不安的眼睛正凝视着你。<br> 它会眨眼，但是它从不闭上自己的眼睛。我们暂时无法得知这个异想体的目的，以及它所凝视着的目标是什么。<br> 经过多次实验，我们发现当有一个或多个员工盯着这个异想体时，情况将会变得非常...非常糟糕...<br> 当你指派员工进入这个异想体的收容单元时，请务必告诉他们千万，千万不要直接看着这个异想体。<br> 如果有蠢蛋问到为什么要这么做，你就跟他们说说“由美”那个没有读过《异想体应对手册》，直视了这个异想体的员工。告诉他们她有着怎样的下场！</p><p>这是一把通体漆黑的电锯，在持有它时，你将会感到无来由的注视，不用担心，这是正常现象<br> 武器伤害：12L 【破甲5】【重型武器】【双手】 攻击造成挥砍伤害<br> 在使用这把武器的时候，你可以将自己的攻击平分至多次攻击投掷，最多拆分至9次（即可以将w90+9拆分为九个w10+1）<br> 每次投掷伤害都需要单独计算防御以及防御上的附加成功的抵消出目和全伤害吸收，并且这次拆分将会在其他资源提供的能力结算之后才进行，因此不会多次计算攻击减值外其他效果，例如：附加严重伤害、易伤、湮灭/毁灭的攻击次数等。<br> 由这把武器造成的伤害会在一段时间内令目标更容易受到挥砍伤害，当你攻击命中时，敌人会受到【挥砍易伤2】持续一场景，这是C级信息来源的效果，<br> 使用这把武器至少不用担心被人伏击，因此具有C级免疫措手不及。</p><p>如果此时你同时持有护甲或者饰品，拆分的攻击投掷会正常计算多次攻击减值，最高9点</p><p>护甲<br> 价格：C+1000<br> 门后的眼睛一直注视着它的目标，没有人能够理解它到底想看到什么。<br> 当你穿上这件护甲后，至少不用担心会被人伏击。<br> 在由美遇到并直视了那个异想体之后，她的状况已经不允许她继续工作了。<br> 我们认为她患上了严重的被害妄想症，她声称自己一直被某个东西监视着。她大部分时间都在重复着诸如“有人在她吃饭或是上洗手间的时候看着她”此类的言论。<br> 当她看见门缝或者锁孔时，就会变得歇斯底里，并试图把这些地方统统封上...不仅如此，更让人恼火的是，她的精神污染程度经系统检测居然处于正常水平！<br> 很明显她已经不能继续正常工作了，但由于她的精神污染程度被判定为正常，所以系统无法“处理”掉她...噢，拜托，请尽快把她调走吧！</p><p>这是一件通体漆黑的甲胄，在中心部位有一个锁孔，其中的眼睛永久注视着周围<br> 它具有盔甲防御10/10<br> 锁孔里面的眼睛注视着你的周围，至少不用担心会被人伏击，<br> 当你的攻击命中敌人时，会按照防御预设-攻击预设-反射豁免-意志豁免-强韧豁免的顺序获得其情报，这个是C级信息来源的解析效果<br> 当你身着这件护甲时，你会获得灵感视觉与黑暗视觉</p><p>饰品<br> 价格：C+1000<br> 哈，问题已经解决了。我们在她的起居室里发现了失踪的她。当我们打开门时，房间内的每一处孔洞，包括通风口，都被她用黑色胶带封住。<br> 她还用钢笔戳瞎了自己的眼睛，说那些幻觉已经全部消失了。谢天谢地，她再没絮絮叨叨那些胡话。<br> 不过有一点我不太能理解，你为什么要把她再送进那个收容单元？先说好，虽然我不知道D-004是什么类型的实验，但我可不认为这会有什么好结果...</p><p>这是一对绒毛般的手套，会占据你的手腕位置<br> 穿戴它会让你从锁孔以及门缝感觉到视线，这是正常情况<br> 穿戴这个饰品会为你带来2点生命上限，以及2点洞察防御<br> 你获得C级魔幻本质的侦测效果</p><p>当你持有以上全部三件装备时，你可以支付<br> C+1000来一次性获得下属能力</p><p>好奇的一撇</p><p>&lt;实验_D-002&gt;<br> 我们将一名员工的眼睛用厚实的黑布蒙上，并确保了光线不会穿透布料。那名员工进入收容单元后，他朝着异想体的方向站立了10秒，异想体没有任何反应。</p><p>&lt;实验_D-003&gt;<br> 与实验_D-002相同，我们将另一名员工的眼睛蒙上，但这次，我们所选用的布条不能完全遮住光线。在员工进入了收容单元后，他朝着异想体的方向站立了10秒。<br> 5秒后，异想体展现出了惊人的攻击性，并快速逼近那名员工。实验被迫中止。</p><p>&lt;实验_D-004&gt;<br> 这次我们没有使用布条，而是派遣了一名盲人员工。他在收容单元内停留了足足30秒，但异想体依然没有任何反应。<br> ※请立即处理掉实验_D-004中的实验对象！</p><p>以一个标准动作启用，对攻击范围内的敌人进行一次攻击检定，正常通过防御，并且可以额外选定2个单位<br> 如果这次攻击的目标具有你的精确定位，此时你的攻击视作具有【8加骰】，并且具有C级措手不及</p><p>监视感</p><p>“不要看它”的警告引起了许多员工的好奇，并最终导致了许多可怕的事故。<br> 当你独自一人时，如果你觉得有什么东西正在凝视着你，那就意味着一切都为时已晚。</p><p>只有在被精准定位的时候才能使用</p><p>现在你的攻击命中会给予敌人【凝视】效果，这是一个C级信息来源的效果<br> 【凝视】：被攻击击中时，会获得一点不可豁免的【监视感】，这是一个C级信息来源的效果<br> 监视感是一种特殊的二档异常点数。需要注意的是，在判断异常点数相关的能力时，该异常点数等同于恐惧点数，但该异常点数的来源改为幻象来源。</p><p>每点【监视感】会在运动检定、攻击检定、基本速度、施展需要动作的法术或类似能力、基础防御+闪避防御+格挡防御的总和上受到士气减值。<br> 抵抗不良状态：意志豁免。<br> 监视感点数超过决心或沉着的较高者，则人物进入恐慌状态。<br> 恐慌状态的人物无法移动，因此速度为0，失去基础防御、无法闪避和格挡，无法使用需要做出身体动作的行为（例如攻击和需要动作成份的法术等）。但他并不被视为无助状态。</p><p>现在，在你使用【好奇的一撇】的时候<br> 你可以额外消耗一个移动动作，此时【好奇的一撇】视作你进行了一个整轮动作<br> 这次使用【好奇的一撇】时，可以以一个自由动作移动不超过移动速度的距离<br> 这次攻击的措手不及升级至B级措手不及<br> 这次【好奇的一撇】将会额外具有【接触攻击】并且可以在移动的同时攻击</p><p>他人的视线</p><p>在机器的锁孔中，你能感受到一只令人不安的眼睛正凝视着你</p><p>只有在被精确定位的时候生效<br> 你每回合开始时，获得只能用于释放【好奇的一撇】的2AP</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',26)])])}const m=a(n,[["render",o]]);export{C as __pageData,m as default};
